declare(strict_types=1);

namespace App\Controller\FrontOffice;

use App\Entity\User;
use App\Form\RegistrationFormType;
use App\Service\EmailService;
use App\Service\AwsFaceRecognitionService;
use Doctrine\ORM\EntityManagerInterface;
use Symfony\Bundle\FrameworkBundle\Controller\AbstractController;
use Symfony\Component\HttpFoundation\Request;
use Symfony\Component\HttpFoundation\Response;
use Symfony\Component\HttpFoundation\Session\SessionInterface;
use Symfony\Component\PasswordHasher\Hasher\UserPasswordHasherInterface;
use Symfony\Component\Routing\Annotation\Route;
use Symfony\Component\Form\FormError;
use Psr\Log\LoggerInterface;

class RegistrationController extends AbstractController
{
    public function __construct(
        private readonly EntityManagerInterface $entityManager,
        private readonly UserPasswordHasherInterface $passwordHasher,
        private readonly EmailService $emailService,
        private readonly AwsFaceRecognitionService $awsFaceService,
        private readonly LoggerInterface $logger,
    ) {
    }

    #[Route('/register', name: 'app_register', methods: ['GET', 'POST'])]
    public function register(Request $request, SessionInterface $session): Response
    {
        $user = new User();
        $form = $this->createForm(RegistrationFormType::class, $user);
        $form->handleRequest($request);

        $allowedRoles = [
            'CANDIDATE' => 'Candidat',
            'RECRUITER' => 'Recruteur',
        ];

        // Debug logging - moved to correct location
        if ($form->isSubmitted()) {
            $this->logger->debug('Form was submitted');

            if (!$form->isValid()) {
                $this->logger->debug('Form validation FAILED');
                // Log all form errors
                foreach ($form->getErrors(true) as $error) {
                    if ($error instanceof FormError) {
                        $this->logger->debug('Form error: ' . $error->getMessage());
                    }
                }
                // Log field errors
                foreach ($form->all() as $child) {
                    foreach ($child->getErrors() as $error) {
                        if ($error instanceof FormError) {
                            $this->logger->debug('Field ' . $child->getName() . ' error: ' . $error->getMessage());
                        }
                    }
                }
            } else {
                $this->logger->debug('Form validation PASSED');
            }
        }

        if ($form->isSubmitted() && $form->isValid()) {
            $firstName = $form->get('firstName')->getData();
            $lastName = $form->get('lastName')->getData();
            $email = $form->get('email')->getData();
            $plainPassword = $form->get('plainPassword')->getData();
            $role = $form->get('role')->getData();
            $phone = $form->get('phone')->getData();

            $faceImage = $request->request->get('face_image');
            $faceImageString = is_string($faceImage) ? $faceImage : '';
            $this->logger->info('Registration data - RAW', [
                'has_face_image' => $request->request->has('face_image'),
                'face_image_length' => strlen($faceImageString),
                'all_post_keys' => array_keys($request->request->all())
            ]);
            $enableFaceEnroll = $request->request->get('enable_face_enroll');
            $enableFaceEnrollString = is_string($enableFaceEnroll) ? $enableFaceEnroll : '0';

            $this->logger->info('Registration data', [
                'has_face_image' => !empty($faceImageString),
                'face_image_length' => strlen($faceImageString),
                'enable_face_enroll' => $enableFaceEnrollString
            ]);

            if (!isset($allowedRoles[$role])) {
                $this->addFlash('danger', 'Invalid account type selected.');
                return $this->render('FrontOffice/security/register.html.twig', [
                    'form' => $form->createView(),
                    'allowed_roles' => $allowedRoles,
                ]);
            }

            $existingUser = $this->entityManager->getRepository(User::class)->findOneBy(['email' => $email]);
            if ($existingUser) {
                $this->addFlash('danger', 'This email is already registered.');
                return $this->render('FrontOffice/security/register.html.twig', [
                    'form' => $form->createView(),
                    'allowed_roles' => $allowedRoles,
                ]);
            }

            $verificationCode = sprintf('%06d', random_int(0, 999999));

            // Save face image to temporary file instead of session
            $tempFaceImagePath = null;
            if ($enableFaceEnrollString === '1' && !empty($faceImageString)) {
                $projectDir = $this->getParameter('kernel.project_dir');
                if (!is_string($projectDir)) {
                    $projectDir = '';
                }
                $tempDir = $projectDir . '/public/uploads/temp_faces';
                if (!file_exists($tempDir)) {
                    mkdir($tempDir, 0777, true);
                }
                $tempFaceImagePath = $tempDir . '/face_' . uniqid() . '.txt';
                file_put_contents($tempFaceImagePath, $faceImageString);
                $this->logger->info('Face image saved to temp file', ['path' => $tempFaceImagePath]);
            }

            // Store registration data in session (without the large face image)
            $session->set('pending_registration', [
                'firstName' => $firstName,
                'lastName' => $lastName,
                'email' => $email,
                'plainPassword' => $plainPassword,
                'role' => $role,
                'phone' => $phone,
                'verificationCode' => $verificationCode,
                'profilePicture' => null,
                'enableFaceEnroll' => $enableFaceEnrollString,
                'tempFaceImagePath' => $tempFaceImagePath,
            ]);

            // Store profile picture if uploaded
            $profilePictureFile = $form->get('profilePicture')->getData();
            if ($profilePictureFile) {
                $projectDir = $this->getParameter('kernel.project_dir');
                if (!is_string($projectDir)) {
                    $projectDir = '';
                }
                $uploadDir = $projectDir . '/public/uploads/temp';
                if (!file_exists($uploadDir)) {
                    mkdir($uploadDir, 0777, true);
                }

                $tempFilename = uniqid() . '.' . $profilePictureFile->guessExtension();
                $profilePictureFile->move($uploadDir, $tempFilename);
                $pendingData = $session->get('pending_registration');
                $pendingData['profilePicture'] = $tempFilename;
                $session->set('pending_registration', $pendingData);
            }

            // Send verification email
            $displayName = $firstName . ' ' . $lastName;
            $emailSent = $this->emailService->sendVerificationCode($email, $displayName, $verificationCode);

            if (!$emailSent) {
                $this->addFlash('danger', 'Failed to send verification email. Please try again.');
                return $this->render('FrontOffice/security/register.html.twig', [
                    'form' => $form->createView(),
                    'allowed_roles' => $allowedRoles,
                ]);
            }

            return $this->render('FrontOffice/security/verify_email.html.twig', [
                'email' => $email,
                'resendUrl' => $this->generateUrl('app_resend_verification'),
            ]);
        }

        // If form is submitted but invalid, or just displaying the form
        return $this->render('FrontOffice/security/register.html.twig', [
            'form' => $form->createView(),
            'allowed_roles' => $allowedRoles,
        ]);
    }

    #[Route('/verify-email', name: 'app_verify_email', methods: ['POST'])]
    public function verifyCode(Request $request, SessionInterface $session): Response
    {
        $verificationCode = $request->request->get('verification_code');
        $pendingData = $session->get('pending_registration');

        $this->logger->info('Verification attempt', [
            'code_submitted' => $verificationCode,
            'has_session' => $pendingData !== null,
            'session_keys' => is_array($pendingData) ? array_keys($pendingData) : []
        ]);

        if (!$pendingData || !is_array($pendingData)) {
            $this->addFlash('danger', 'No pending registration found. Please register again.');
            return $this->redirectToRoute('app_register');
        }

        /** @var array{firstName:mixed,lastName:mixed,email:mixed,plainPassword:mixed,role:mixed,phone?:mixed,verificationCode:mixed,profilePicture?:mixed,enableFaceEnroll:mixed,tempFaceImagePath?:mixed} $pendingData */

        $verificationCodeString = is_string($verificationCode) ? $verificationCode : '';
        if ((string)$pendingData['verificationCode'] !== $verificationCodeString) {
            $this->addFlash('danger', 'Invalid verification code. Please try again.');
            return $this->render('FrontOffice/security/verify_email.html.twig', [
                'email' => $pendingData['email'],
                'resendUrl' => $this->generateUrl('app_resend_verification'),
            ]);
        }

        // Create user
        $user = new User();
        $user->setFirstName((string) $pendingData['firstName']);
        $user->setLastName((string) $pendingData['lastName']);
        $user->setEmail((string) $pendingData['email']);
        $role = $pendingData['role'];
        $user->setRoles('ROLE_' . (string) $role);
        $user->setType((string) $role);
        $user->setIsActive(1);
        $user->setCreatedAt(new \DateTimeImmutable());
        $user->setFaceEnabled(0);
        $user->setIsVerified(true);

        if (!empty($pendingData['phone'])) {
            $user->setPhone((string) $pendingData['phone']);
        }

        // Set default values
        $user->setHeadline('');
        $user->setBio('');
        $user->setLocation('');
        $user->setVisibility('public');
        $user->setNiveau('');
        $user->setScoreGlobal(0);
        $user->setOrgName('');
        $user->setDescription('');
        $user->setWebsiteUrl('');
        $user->setLogoUrl('');
        $user->setSchool('');
        $user->setDegree('');
        $user->setFieldOfStudy('');
        $user->setGraduationYear(0);
        $user->setHardSkills('');
        $user->setSoftSkills('');
        $user->setGithubUrl('');
        $user->setPortfolioUrl('');
        $user->setFacePersonId('');

        // Handle profile picture
        if (isset($pendingData['profilePicture']) && $pendingData['profilePicture']) {
            $projectDir = $this->getParameter('kernel.project_dir');
            if (!is_string($projectDir)) {
                $projectDir = '';
            }
            $profilePicture = (string) $pendingData['profilePicture'];
            $tempFile = $projectDir . '/public/uploads/temp/' . $profilePicture;
            $targetDir = $projectDir . '/public/uploads/profile-pictures';

            if (!file_exists($targetDir)) {
                mkdir($targetDir, 0777, true);
            }

            $targetFile = $targetDir . '/' . $profilePicture;
            if (file_exists($tempFile)) {
                rename($tempFile, $targetFile);
                $user->setProfilePic('/uploads/profile-pictures/' . $profilePicture);
            }
        }

        // Hash password
        $hashedPassword = $this->passwordHasher->hashPassword($user, $pendingData['plainPassword']);
        $user->setPasswordHash($hashedPassword);

        try {
            $this->entityManager->persist($user);
            $this->entityManager->flush();

            $this->logger->info('User saved', ['userId' => $user->getId()]);

            // Handle face enrollment - read from temp file
            $enableFaceEnroll = is_string($pendingData['enableFaceEnroll'] ?? '0') ? $pendingData['enableFaceEnroll'] : '0';
            $faceImage = null;

            if ($enableFaceEnroll === '1' && isset($pendingData['tempFaceImagePath'])) {
                $tempFacePath = $pendingData['tempFaceImagePath'];
                if (is_string($tempFacePath) && file_exists($tempFacePath)) {
                    $faceImage = file_get_contents($tempFacePath);
                    $this->logger->info('Face image loaded from temp file', [
                        'path' => $tempFacePath,
                        'length' => is_string($faceImage) ? strlen($faceImage) : 0
                    ]);
                    // Clean up temp file
                    unlink($tempFacePath);
                } else {
                    $this->logger->warning('Temp face file not found', ['path' => $tempFacePath]);
                }
            }

            $faceImageString = is_string($faceImage) ? $faceImage : '';
            $this->logger->info('Face enrollment check', [
                'enable' => $enableFaceEnroll,
                'has_image' => !empty($faceImageString),
                'image_length' => strlen($faceImageString)
            ]);

            if ($enableFaceEnroll === '1' && !empty($faceImageString)) {
                $userId = $user->getId();
                if ($userId) {
                    $this->logger->info('Calling face enrollment', ['userId' => $userId]);
                }

                // Clean the face image
                $cleanFaceImage = preg_replace('/^data:image\/\w+;base64,/', '', $faceImageString);
                $cleanFaceImageString = is_string($cleanFaceImage) ? $cleanFaceImage : '';
                $faceResult = $this->awsFaceService->enrollFace($user, $cleanFaceImageString);

                if ($faceResult['success']) {
                    $this->logger->info('Face enrollment SUCCESS', ['faceId' => $faceResult['faceId'] ?? '']);
                    $this->addFlash('success', 'Face ID has been enabled!');
                } else {
                    $errorMessage = (string) ($faceResult['error'] ?? 'Unknown error');
                    $this->logger->error('Face enrollment FAILED', ['error' => $errorMessage]);
                    $this->addFlash('warning', 'Face enrollment failed: ' . $errorMessage);
                }
            }

            // Clear session
            $session->remove('pending_registration');

            $this->addFlash('success', 'Account created successfully! You can now log in.');
            return $this->redirectToRoute('app_login');

        } catch (\Exception $e) {
            $this->logger->error('User creation failed', ['error' => $e->getMessage()]);
            $this->addFlash('danger', 'Error: ' . $e->getMessage());
            return $this->redirectToRoute('app_register');
        }
    }

    #[Route('/resend-verification', name: 'app_resend_verification', methods: ['POST'])]
    public function resendVerification(Request $request, SessionInterface $session): Response
    {
        $pendingData = $session->get('pending_registration');

        if (!$pendingData) {
            $this->addFlash('danger', 'No pending registration found. Please register again.');
            return $this->redirectToRoute('app_register');
        }

        $newCode = sprintf('%06d', random_int(0, 999999));
        $pendingData['verificationCode'] = $newCode;
        $session->set('pending_registration', $pendingData);

        $displayName = $pendingData['firstName'] . ' ' . $pendingData['lastName'];
        $emailSent = $this->emailService->sendVerificationCode($pendingData['email'], $displayName, $newCode);

        if ($emailSent) {
            $this->addFlash('success', 'A new verification code has been sent to your email.');
        } else {
            $this->addFlash('danger', 'Failed to send verification email. Please try again.');
        }

        return $this->render('FrontOffice/security/verify_email.html.twig', [
            'email' => $pendingData['email'],
            'resendUrl' => $this->generateUrl('app_resend_verification'),
        ]);
    }
}

{% extends 'FrontOffice/main/base_candidate.html.twig' %}

{% block title %}{{ cours.titre|default('Détail du cours')|trans_lang }}{% endblock %}

{% block stylesheets %}
    {{ parent() }}
    <link rel="stylesheet" href="{{ asset('FrontOffice/css/front-overrides.css') }}?v=20260409-1">
{% endblock %}

{% block candidate_page_heading %}{{ 'Détail du cours'|trans_lang }}{% endblock %}

{% block candidate_breadcrumb %}
    / <a href="{{ path('app_candidate_cours') }}">{{ 'Cours'|trans_lang }}</a> / {{ cours.titre|default('Détail')|trans_lang }}
{% endblock %}

{% block candidate_content %}
    {% set active_lesson = continue_lesson|default(null) %}
    {% if active_lesson is null %}
        {% for module in modules %}
            {% set module_lessons = lessons_by_module[module.id]|default([]) %}
            {% if active_lesson is null and module_lessons is not empty %}
                {% set active_lesson = module_lessons|first %}
            {% endif %}
        {% endfor %}
    {% endif %}

    <div class="w-100 text-start fo-charte-ui">
        <div class="d-flex justify-content-between align-items-center flex-wrap mb-3">
            <a href="{{ path('app_candidate_cours') }}" class="btn btn-outline-secondary btn-sm mb-2">
                {{ 'Retour aux cours'|trans_lang }}
            </a>
            <div class="text-muted mb-2">
                {{ 'Progression globale'|trans_lang }} : <strong>{{ progress|default(0) }}%</strong>
            </div>
        </div>

        <div class="row g-4 fo-player-layout">
            <div class="col-lg-3 fo-player-layout__left">
                {% include 'FrontOffice/main/partials/_course_sidebar.html.twig' with {
                    cours: cours,
                    modules: modules,
                    lessons_by_module: lessons_by_module,
                    viewed_lesson_ids: viewed_lesson_ids,
                    active_lesson_id: active_lesson ? active_lesson.id : null
                } only %}
            </div>

            <div class="col-lg-9">
                <div class="card shadow-sm fo-charte-card mb-4">
                    {% if cours.imageCouverture %}
                        <img src="{{ path('app_candidate_cours_image', {id: cours.id}) }}"
                             class="card-img-top"
                             alt="{{ cours.titre|default('Cours') }}"
                             style="max-height: 260px; object-fit: cover;">
                    {% endif %}
                    <div class="card-body">
                        <div class="d-flex justify-content-between align-items-start flex-wrap mb-3">
                            <div>
                                <h3 class="mb-1">{{ cours.titre|default('Cours')|trans_lang }}</h3>
                                <p class="text-muted mb-0">{{ cours.description|default('Aucune description')|trans_lang }}</p>
                            </div>
                            <span class="badge badge-{{ cours.niveau == 'Débutant' ? 'success' : (cours.niveau == 'Intermédiaire' ? 'warning' : 'danger') }}">
                                {{ cours.niveau|default('—')|trans_lang }}
                            </span>
                        </div>

                        <div class="row text-center">
                            <div class="col-md-4 mb-3 mb-md-0">
                                <div class="p-3 bg-light rounded">
                                    <small class="d-block text-muted">{{ 'Durée'|trans_lang }}</small>
                                    <strong>{{ cours.duree|default('—') }} h</strong>
                                </div>
                            </div>
                            <div class="col-md-4 mb-3 mb-md-0">
                                <div class="p-3 bg-light rounded">
                                    <small class="d-block text-muted">{{ 'Quiz validés'|trans_lang }}</small>
                                    <strong>{{ quiz_passed_count|default(0) }}/{{ quiz_total_count|default(0) }}</strong>
                                </div>
                            </div>
                            <div class="col-md-4">
                                <div class="p-3 bg-light rounded">
                                    <small class="d-block text-muted">{{ 'Test final'|trans_lang }}</small>
                                    <strong>{{ (final_test_unlocked|default(false) ? 'Débloqué' : 'Bloqué')|trans_lang }}</strong>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>

                <div class="card shadow-sm fo-charte-card mb-4">
                    <div class="card-header fo-charte-header d-flex justify-content-between align-items-center flex-wrap">
                        <strong>{{ 'Leçon en cours'|trans_lang }}</strong>
                        {% if continue_lesson is defined and continue_lesson %}
                            <small class="text-muted">
                                {{ 'Prochaine leçon'|trans_lang }}: {{ continue_lesson.titre|default('—')|trans_lang }}
                            </small>
                        {% endif %}
                    </div>
                    <div class="card-body">
                        {% if active_lesson %}
                            <div class="d-flex justify-content-between align-items-start flex-wrap mb-3">
                                <div>
                                    <h4 class="mb-1">{{ active_lesson.titre|default('Leçon')|trans_lang }}</h4>
                                    <small class="text-muted">{{ active_lesson.module ? active_lesson.module.titre|trans_lang : '—' }}</small>
                                </div>
                                {% if viewed_lesson_ids[active_lesson.id]|default(false) %}
                                    <span class="badge badge-success">{{ 'Vue'|trans_lang }}</span>
                                {% endif %}
                            </div>

                            {% if active_lesson.video %}
                                <div class="mb-3">
                                    <video controls class="w-100" style="max-height: 460px;">
                                        <source src="{{ path('app_candidate_lecon_video', {cours: cours.id, id: active_lesson.id}) }}" type="video/mp4">
                                        {{ 'Votre navigateur ne supporte pas la lecture vidéo.'|trans_lang }}
                                    </video>
                                </div>
                            {% endif %}

                            <div class="p-3 bg-light rounded">{{ active_lesson.contenu|default('—')|nl2br }}</div>
                        {% else %}
                            <div class="alert alert-light border mb-0">{{ 'Aucune leçon à afficher pour le moment.'|trans_lang }}</div>
                        {% endif %}
                    </div>
                </div>

                <div class="card shadow-sm fo-charte-card">
                    <div class="card-body d-flex justify-content-between align-items-center flex-wrap">
                        <div class="mb-2 mb-md-0">
                            <strong>{{ 'Progression globale'|trans_lang }} :</strong> {{ progress|default(0) }}%
                            <div class="progress mt-2" style="height: 10px; min-width: 260px;">
                                <div class="progress-bar bg-success" role="progressbar"
                                     style="width: {{ progress|default(0) }}%;"
                                     aria-valuenow="{{ progress|default(0) }}"
                                     aria-valuemin="0" aria-valuemax="100"></div>
                            </div>
                        </div>

                        {% if final_test_unlocked|default(false) %}
                            <a href="{{ path('app_candidate_cours_test_final', {id: cours.id}) }}" class="btn btn-primary">
                                {{ 'Passer le test final (15 questions)'|trans_lang }}
                            </a>
                        {% else %}
                            <button type="button" class="btn btn-secondary" disabled>
                                {{ 'Test final bloqué'|trans_lang }}
                            </button>
                        {% endif %}
                    </div>
                </div>
            </div>
        </div>
    </div>
{% endblock %}

{% extends 'FrontOffice/main/base_candidate.html.twig' %}

{% block title %}{{ cours.titre|default('Détail du cours')|trans_lang }}{% endblock %}

{% block stylesheets %}
    {{ parent() }}
    <link rel="stylesheet" href="{{ asset('FrontOffice/css/front-overrides.css') }}?v=20260409-1">
{% endblock %}

{% block candidate_page_heading %}{{ 'Détail du cours'|trans_lang }}{% endblock %}

{% block candidate_breadcrumb %}
    / <a href="{{ path('app_candidate_cours') }}">{{ 'Cours'|trans_lang }}</a> / {{ cours.titre|default('Détail')|trans_lang }}
{% endblock %}

{% block candidate_content %}
    {% set active_lesson = continue_lesson|default(null) %}
    {% if active_lesson is null %}
        {% for module in modules %}
            {% set module_lessons = lessons_by_module[module.id]|default([]) %}
            {% if active_lesson is null and module_lessons is not empty %}
                {% set active_lesson = module_lessons|first %}
            {% endif %}
        {% endfor %}
    {% endif %}

    <div class="w-100 text-start fo-charte-ui">
        <div class="d-flex justify-content-between align-items-center flex-wrap mb-3">
            <a href="{{ path('app_candidate_cours') }}" class="btn btn-outline-secondary btn-sm mb-2">
                {{ 'Retour aux cours'|trans_lang }}
            </a>
            <div class="text-muted mb-2">
                {{ 'Progression globale'|trans_lang }} : <strong>{{ progress|default(0) }}%</strong>
            </div>
        </div>

        <div class="row g-4 fo-player-layout">
            <div class="col-lg-3 fo-player-layout__left">
                {% include 'FrontOffice/main/partials/_course_sidebar.html.twig' with {
                    cours: cours,
                    modules: modules,
                    lessons_by_module: lessons_by_module,
                    viewed_lesson_ids: viewed_lesson_ids,
                    active_lesson_id: active_lesson ? active_lesson.id : null
                } only %}
            </div>

            <div class="col-lg-9">
                <div class="card shadow-sm fo-charte-card mb-4">
                    {% if cours.imageCouverture %}
                        <img src="{{ path('app_candidate_cours_image', {id: cours.id}) }}"
                             class="card-img-top"
                             alt="{{ cours.titre|default('Cours') }}"
                             style="max-height: 260px; object-fit: cover;">
                    {% endif %}
                    <div class="card-body">
                        <div class="d-flex justify-content-between align-items-start flex-wrap mb-3">
                            <div>
                                <h3 class="mb-1">{{ cours.titre|default('Cours')|trans_lang }}</h3>
                                <p class="text-muted mb-0">{{ cours.description|default('Aucune description')|trans_lang }}</p>
                            </div>
                            <span class="badge badge-{{ cours.niveau == 'Débutant' ? 'success' : (cours.niveau == 'Intermédiaire' ? 'warning' : 'danger') }}">
                                {{ cours.niveau|default('—')|trans_lang }}
                            </span>
                        </div>

                        <div class="row text-center">
                            <div class="col-md-4 mb-3 mb-md-0">
                                <div class="p-3 bg-light rounded">
                                    <small class="d-block text-muted">{{ 'Durée'|trans_lang }}</small>
                                    <strong>{{ cours.duree|default('—') }} h</strong>
                                </div>
                            </div>
                            <div class="col-md-4 mb-3 mb-md-0">
                                <div class="p-3 bg-light rounded">
                                    <small class="d-block text-muted">{{ 'Quiz validés'|trans_lang }}</small>
                                    <strong>{{ quiz_passed_count|default(0) }}/{{ quiz_total_count|default(0) }}</strong>
                                </div>
                            </div>
                            <div class="col-md-4">
                                <div class="p-3 bg-light rounded">
                                    <small class="d-block text-muted">{{ 'Test final'|trans_lang }}</small>
                                    <strong>{{ (final_test_unlocked|default(false) ? 'Débloqué' : 'Bloqué')|trans_lang }}</strong>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>

                <div class="card shadow-sm fo-charte-card mb-4">
                    <div class="card-header fo-charte-header d-flex justify-content-between align-items-center flex-wrap">
                        <strong>{{ 'Leçon en cours'|trans_lang }}</strong>
                        {% if continue_lesson is defined and continue_lesson %}
                            <small class="text-muted">
                                {{ 'Prochaine leçon'|trans_lang }}: {{ continue_lesson.titre|default('—')|trans_lang }}
                            </small>
                        {% endif %}
                    </div>
                    <div class="card-body">
                        {% if active_lesson %}
                            <div class="d-flex justify-content-between align-items-start flex-wrap mb-3">
                                <div>
                                    <h4 class="mb-1">{{ active_lesson.titre|default('Leçon')|trans_lang }}</h4>
                                    <small class="text-muted">{{ active_lesson.module ? active_lesson.module.titre|trans_lang : '—' }}</small>
                                </div>
                                {% if viewed_lesson_ids[active_lesson.id]|default(false) %}
                                    <span class="badge badge-success">{{ 'Vue'|trans_lang }}</span>
                                {% endif %}
                            </div>

                            {% if active_lesson.video %}
                                <div class="mb-3">
                                    <video controls class="w-100" style="max-height: 460px;">
                                        <source src="{{ path('app_candidate_lecon_video', {cours: cours.id, id: active_lesson.id}) }}" type="video/mp4">
                                        {{ 'Votre navigateur ne supporte pas la lecture vidéo.'|trans_lang }}
                                    </video>
                                </div>
                            {% endif %}

                            <div class="p-3 bg-light rounded">{{ active_lesson.contenu|default('—')|nl2br }}</div>
                        {% else %}
                            <div class="alert alert-light border mb-0">{{ 'Aucune leçon à afficher pour le moment.'|trans_lang }}</div>
                        {% endif %}
                    </div>
                </div>

                <div class="card shadow-sm fo-charte-card">
                    <div class="card-body d-flex justify-content-between align-items-center flex-wrap">
                        <div class="mb-2 mb-md-0">
                            <strong>{{ 'Progression globale'|trans_lang }} :</strong> {{ progress|default(0) }}%
                            <div class="progress mt-2" style="height: 10px; min-width: 260px;">
                                <div class="progress-bar bg-success" role="progressbar"
                                     style="width: {{ progress|default(0) }}%;"
                                     aria-valuenow="{{ progress|default(0) }}"
                                     aria-valuemin="0" aria-valuemax="100"></div>
                            </div>
                        </div>

                        {% if final_test_unlocked|default(false) %}
                            <a href="{{ path('app_candidate_cours_test_final', {id: cours.id}) }}" class="btn btn-primary">
                                {{ 'Passer le test final (22 questions)'|trans_lang }}
                            </a>
                        {% else %}
                            <button type="button" class="btn btn-secondary" disabled>
                                {{ 'Test final bloqué'|trans_lang }}
                            </button>
                        {% endif %}
                    </div>
                </div>
            </div>
        </div>
    </div>
{% endblock %}

{# Shared left sidebar for cours_show and lecon_show (FXML-like: header + scroll list) #}
<div class="fo-player-sidebar card shadow-sm fo-charte-card position-sticky">
    <div class="card-header fo-charte-header fo-player-sidebar__header">
        <div class="d-flex justify-content-between align-items-center">
            <span class="font-weight-bold">{{ 'Modules du cours'|trans_lang }}</span>
            <span class="badge badge-light">{{ modules|length }}</span>
        </div>
    </div>

    <div class="fo-player-sidebar__scroll">
        {% for module in modules %}
            {% set module_lessons = lessons_by_module[module.id]|default([]) %}
            {% set can_take_module_quiz = module_lessons|length > 0 %}
            {% if can_take_module_quiz %}
                {% for lesson in module_lessons %}
                    {% if not viewed_lesson_ids[lesson.id]|default(false) %}
                        {% set can_take_module_quiz = false %}
                    {% endif %}
                {% endfor %}
            {% endif %}
            <div class="fo-player-module">
                <div class="d-flex justify-content-between align-items-start mb-2">
                    <div class="pr-2" style="min-width: 0;">
                        <div class="fo-player-module__index">{{ 'Module'|trans_lang }} {{ module.ordre|default(loop.index) }}</div>
                        <div class="fo-player-module__title">{{ module.titre|default('Sans titre')|trans_lang }}</div>
                    </div>
                    <span class="badge badge-light fo-player-module__count">{{ module_lessons|length }}</span>
                </div>

                <div class="mb-2">
                    {% for lesson in module_lessons %}
                        <a href="{{ path('app_candidate_lecon_show', {cours: cours.id, id: lesson.id}) }}"
                           class="fo-player-lesson-link d-flex justify-content-between align-items-center {{ active_lesson_id is defined and active_lesson_id == lesson.id ? 'is-active text-white' : 'text-dark' }}">
                            <span class="fo-player-lesson-link__title">{{ lesson.titre|default('Leçon')|trans_lang }}</span>
                            {% if viewed_lesson_ids[lesson.id]|default(false) %}
                                <span class="fo-player-lesson-link__check">✓</span>
                            {% endif %}
                        </a>
                    {% endfor %}
                </div>

                {% if can_take_module_quiz %}
                    <a href="{{ path('app_candidate_module_quiz', {id: module.id}) }}" class="btn btn-sm btn-outline-primary btn-block fo-player-module__quiz-btn">
                        {{ 'Quiz module'|trans_lang }} (5)
                    </a>
                {% else %}
                    <button type="button" class="btn btn-sm btn-secondary btn-block fo-player-module__quiz-btn" disabled>
                        {{ 'Quiz verrouillé'|trans_lang }}
                    </button>
                {% endif %}
            </div>
        {% else %}
            <div class="p-3 text-muted">{{ 'Aucun module disponible.'|trans_lang }}</div>
        {% endfor %}
    </div>
</div>

{# Shared left sidebar for cours_show and lecon_show (FXML-like: header + scroll list) #}
<div class="fo-player-sidebar card shadow-sm fo-charte-card position-sticky">
    <div class="card-header fo-charte-header fo-player-sidebar__header">
        <div class="d-flex justify-content-between align-items-center">
            <span class="font-weight-bold">{{ 'Modules du cours'|trans_lang }}</span>
            <span class="badge badge-light">{{ modules|length }}</span>
        </div>
    </div>

    <div class="fo-player-sidebar__scroll">
        {% for module in modules %}
            {% set module_lessons = lessons_by_module[module.id]|default([]) %}
            {% set can_take_module_quiz = module_lessons|length > 0 %}
            {% if can_take_module_quiz %}
                {% for lesson in module_lessons %}
                    {% if not viewed_lesson_ids[lesson.id]|default(false) %}
                        {% set can_take_module_quiz = false %}
                    {% endif %}
                {% endfor %}
            {% endif %}
            <div class="fo-player-module">
                <div class="d-flex justify-content-between align-items-start mb-2">
                    <div class="pr-2" style="min-width: 0;">
                        <div class="fo-player-module__index">{{ 'Module'|trans_lang }} {{ module.ordre|default(loop.index) }}</div>
                        <div class="fo-player-module__title">{{ module.titre|default('Sans titre')|trans_lang }}</div>
                    </div>
                    <span class="badge badge-light fo-player-module__count">{{ module_lessons|length }}</span>
                </div>

                <div class="mb-2">
                    {% for lesson in module_lessons %}
                        <a href="{{ path('app_candidate_lecon_show', {cours: cours.id, id: lesson.id}) }}"
                           class="fo-player-lesson-link d-flex justify-content-between align-items-center {{ active_lesson_id is defined and active_lesson_id == lesson.id ? 'is-active text-white' : 'text-dark' }}">
                            <span class="fo-player-lesson-link__title">{{ lesson.titre|default('Leçon')|trans_lang }}</span>
                            {% if viewed_lesson_ids[lesson.id]|default(false) %}
                                <span class="fo-player-lesson-link__check">✓</span>
                            {% endif %}
                        </a>
                    {% endfor %}
                </div>

                {% if can_take_module_quiz %}
                    <a href="{{ path('app_candidate_module_quiz', {id: module.id}) }}" class="btn btn-sm btn-outline-primary btn-block fo-player-module__quiz-btn">
                        {{ 'Quiz module'|trans_lang }} (12)
                    </a>
                {% else %}
                    <button type="button" class="btn btn-sm btn-secondary btn-block fo-player-module__quiz-btn" disabled>
                        {{ 'Quiz verrouillé'|trans_lang }}
                    </button>
                {% endif %}
            </div>
        {% else %}
            <div class="p-3 text-muted">{{ 'Aucun module disponible.'|trans_lang }}</div>
        {% endfor %}
    </div>
</div>
